package main

import (
	"bytes"
	"database/sql"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
	"time"

	_ "modernc.org/sqlite"
)

const (
	token       = "REDACTED"
	apiURL      = "http://127.0.0.1:8090/api/wallets/transfer"
	dbPath      = "/home/user/myproject/pb_data/data.db"
	fromWallet  = "x8fqd2xayvmiupa"
	toWallet    = "8nzg5qtvsacgn3w"
	totalReqs   = 50
	numWorkers  = 10
)

type TransferRequest struct {
	FromId string  `json:"fromId"`
	ToId   string  `json:"toId"`
	Amount float64 `json:"amount"`
}

type TransferResponse struct {
	FromBalance float64 `json:"fromBalance"`
	ToBalance   float64 `json:"toBalance"`
}

func main() {
	// Reset DB first to ensure consistent start
	db, err := sql.Open("sqlite", dbPath)
	if err != nil {
		log.Fatal("Failed to open db:", err)
	}
	defer db.Close()

	_, err = db.Exec("UPDATE wallets SET balance=100 WHERE id=?", fromWallet)
	if err != nil {
		log.Fatal("Failed to reset fromWallet:", err)
	}
	_, err = db.Exec("UPDATE wallets SET balance=0 WHERE id=?", toWallet)
	if err != nil {
		log.Fatal("Failed to reset toWallet:", err)
	}
	_, err = db.Exec("DELETE FROM transfers")
	if err != nil {
		log.Fatal("Failed to clear transfers:", err)
	}

	log.Println("Database reset. Starting concurrency test...")

	// Channels for coordinating workers
	jobs := make(chan int, totalReqs)
	results := make(chan error, totalReqs)

	startTime := time.Now()

	var wg sync.WaitGroup
	// Start 10 workers
	for w := 1; w <= numWorkers; w++ {
		wg.Add(1)
		go func(workerID int) {
			defer wg.Done()
			client := &http.Client{
				Timeout: 10 * time.Second,
			}

			for range jobs {
				reqBody, _ := json.Marshal(TransferRequest{
					FromId: fromWallet,
					ToId:   toWallet,
					Amount: 1,
				})

				req, err := http.NewRequest("POST", apiURL, bytes.NewBuffer(reqBody))
				if err != nil {
					results <- err
					continue
				}

				req.Header.Set("Content-Type", applicationJSON())
				req.Header.Set("Authorization", token)

				resp, err := client.Do(req)
				if err != nil {
					results <- err
					continue
				}

				bodyBytes, _ := io.ReadAll(resp.Body)
				resp.Body.Close()

				if resp.StatusCode != http.StatusOK {
					results <- fmt.Errorf("worker %d got status %d: %s", workerID, resp.StatusCode, string(bodyBytes))
					continue
				}

				results <- nil
			}
		}(w)
	}

	// Send 50 jobs
	for i := 1; i <= totalReqs; i++ {
		jobs <- i
	}
	close(jobs)

	// Wait for workers to finish
	wg.Wait()
	close(results)

	duration := time.Since(startTime)
	log.Printf("All requests completed in %v\n", duration)

	// Verify results
	failedCount := 0
	for err := range results {
		if err != nil {
			log.Println("Request failed:", err)
			failedCount++
		}
	}

	// Query final state from DB
	var finalFromBalance, finalToBalance float64
	err = db.QueryRow("SELECT balance FROM wallets WHERE id=?", fromWallet).Scan(&finalFromBalance)
	if err != nil {
		log.Fatal(err)
	}
	err = db.QueryRow("SELECT balance FROM wallets WHERE id=?", toWallet).Scan(&finalToBalance)
	if err != nil {
		log.Fatal(err)
	}

	var transfersCount int
	err = db.QueryRow("SELECT COUNT(*) FROM transfers").Scan(&transfersCount)
	if err != nil {
		log.Fatal(err)
	}

	log.Println("-------------------------------------------")
	log.Printf("Total Requests: %d\n", totalReqs)
	log.Printf("Failed Requests: %d\n", failedCount)
	log.Printf("Final Wallet A Balance: %f (expected: 50.0)\n", finalFromBalance)
	log.Printf("Final Wallet B Balance: %f (expected: 50.0)\n", finalToBalance)
	log.Printf("Total Rows in transfers: %d (expected: 50)\n", transfersCount)
	log.Printf("Execution time: %v (expected: < 30s)\n", duration)
	log.Println("-------------------------------------------")

	if failedCount > 0 {
		log.Fatalf("Test FAILED: %d requests failed", failedCount)
	}
	if finalFromBalance != 50.0 || finalToBalance != 50.0 {
		log.Fatalf("Test FAILED: Final balances mismatch")
	}
	if transfersCount != 50 {
		log.Fatalf("Test FAILED: Transfers row count mismatch")
	}
	if duration >= 30*time.Second {
		log.Fatalf("Test FAILED: Execution took longer than 30 seconds")
	}

	log.Println("CONCURRENCY TEST PASSED SUCCESSFULLY!")
}

func applicationJSON() string {
	return "application/json"
